SELECT EnglishProductName
FROM [dbo].[DimProduct]
WHERE Color = 'Red';

SELECT CustomerKey, Gender, YearlyIncome
FROM [dbo].[DimCustomer]
WHERE Gender = 'F' AND YearlyIncome > 100000;

SELECT CustomerKey, FirstName, LastName, TotalChildren
FROM [dbo].[DimCustomer]
WHERE TotalChildren >= 5;

SELECT CustomerKey, BirthDate
FROM [dbo].[DimCustomer]
WHERE YEAR(BirthDate) = 1970;

SELECT ProductKey, EnglishProductName, ListPrice
FROM [dbo].[DimProduct]
WHERE ListPrice > 1000;
